import type {ErrorNoParams, Vocabulary} from "../../types"
import additionalItems, {AdditionalItemsError} from "./additionalItems.js"
import prefixItems from "./prefixItems.js"
import items from "./items.js"
import items2020, {ItemsError} from "./items2020.js"
import contains, {ContainsError} from "./contains.js"
import dependencies, {DependenciesError} from "./dependencies.js"
import propertyNames, {PropertyNamesError} from "./propertyNames.js"
import additionalProperties, {AdditionalPropertiesError} from "./additionalProperties.js"
import properties from "./properties.js"
import patternProperties from "./patternProperties.js"
import notKeyword, {NotKeywordError} from "./not.js"
import anyOf, {AnyOfError} from "./anyOf.js"
import oneOf, {OneOfError} from "./oneOf.js"
import allOf from "./allOf.js"
import ifKeyword, {IfKeywordError} from "./if.js"
import thenElse from "./thenElse.js"

export default function getApplicator(draft2020 = false): Vocabulary {
  const applicator = [
    // any
    notKeyword,
    anyOf,
    oneOf,
    allOf,
    ifKeyword,
    thenElse,
    // object
    propertyNames,
    additionalProperties,
    dependencies,
    properties,
    patternProperties,
  ]
  // array
  if (draft2020) applicator.push(prefixItems, items2020)
  else applicator.push(additionalItems, items)
  applicator.push(contains)
  return applicator
}

export type ApplicatorKeywordError =
  | ErrorNoParams<"false schema">
  | AdditionalItemsError
  | ItemsError
  | ContainsError
  | AdditionalPropertiesError
  | DependenciesError
  | IfKeywordError
  | AnyOfError
  | OneOfError
  | NotKeywordError
  | PropertyNamesError
